def gen(rng, size):
    n = size
    edges = []
    for i in range(1, n):
        parent = rng.randint(0, i - 1)
        if rng.random() < 0.5:
            edges.append([parent, i])
        else:
            edges.append([i, parent])
    return [n, edges]

