class Solution:
    def minReorder(self, n, connections):
        from collections import defaultdict, deque
        graph = defaultdict(list)
        original = set()
        for a, b in connections:
            graph[a].append(b)
            graph[b].append(a)
            original.add((a, b))
        visited = [False] * n
        queue = deque([0])
        visited[0] = True
        count = 0
        while queue:
            node = queue.popleft()
            for nb in graph[node]:
                if not visited[nb]:
                    visited[nb] = True
                    if (node, nb) in original:
                        count += 1
                    queue.append(nb)
        return count

